INSERT INTO instructors (id, user_id, slug, bio, avatar_url, linkedin_url, github_url, twitter_url, specialty, years_experience, total_students, rating) VALUES
(1, 2, 'lucia-romero', 'Ingeniera frontend senior especializada en React, Astro y sistemas de diseño. Ha liderado migraciones de aplicaciones monolíticas a arquitecturas por componentes con foco en rendimiento, accesibilidad y experiencia de usuario.', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?auto=format&fit=crop&w=400&q=80', 'https://linkedin.com/in/luciaromero', 'https://github.com/luciaromero', 'https://twitter.com/luciaromero', 'Frontend Architecture', 9, 18400, 4.92),
(2, 3, 'javier-ortega', 'Arquitecto backend con experiencia en APIs REST, PHP, Node.js, MySQL y seguridad aplicada. Su enfoque combina modelado de datos, contratos HTTP claros y despliegues estables para proyectos reales.', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?auto=format&fit=crop&w=400&q=80', 'https://linkedin.com/in/javierortega', 'https://github.com/javierortega', 'https://twitter.com/javierortega', 'Backend & APIs', 11, 22100, 4.88),
(3, 4, 'marta-salas', 'Product engineer centrada en TypeScript, DX y calidad. Trabaja conectando necesidades de negocio con decisiones técnicas mantenibles, testing y documentación útil para equipos pequeños.', 'https://images.unsplash.com/photo-1517841905240-472988babdf9?auto=format&fit=crop&w=400&q=80', 'https://linkedin.com/in/martasalas', 'https://github.com/martasalas', 'https://twitter.com/martasalas', 'TypeScript & Product Engineering', 8, 15600, 4.9),
(4, 5, 'diego-martin', 'DevOps engineer especializado en Docker, CI/CD, Vercel, Railway y observabilidad. Ayuda a equipos a pasar de despliegues manuales a pipelines repetibles y monitorizados.', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?auto=format&fit=crop&w=400&q=80', 'https://linkedin.com/in/diegomartin', 'https://github.com/diegomartin', 'https://twitter.com/diegomartin', 'DevOps & Cloud', 10, 13200, 4.86);
INSERT INTO courses (id, title, description, slug, price, level, category_id, instructor_id, created_by, thumbnail_url, duration_hours, total_lessons, total_students, rating, requirements, what_you_learn, curriculum) VALUES
(1, 'React Avanzado', 'React Avanzado es un curso práctico para developers que ya conocen componentes, props y estado, pero necesitan construir aplicaciones mantenibles. Durante el curso se trabaja con composición, hooks personalizados, gestión de estado, rendimiento, formularios complejos, separación por dominios y patrones de arquitectura frontend. La idea no es memorizar APIs, sino entender cómo tomar decisiones cuando una pantalla crece, cuando aparecen efectos secundarios, cuando varios equipos tocan los mismos componentes y cuando el rendimiento empieza a importar. El proyecto final consiste en una plataforma de cursos con carrito, autenticación visual, filtros y consumo de datos externos. Cada módulo añade una pieza real: estructura de carpetas, componentes reutilizables, control de renderizados, accesibilidad y pruebas. Al terminar tendrás criterios para defender por qué usas un contexto, cuándo conviene extraer un hook y cómo evitar componentes gigantes difíciles de mantener.', 'react-avanzado', 49.99, 'Avanzado', 1, 1, 2, 'https://images.unsplash.com/photo-1633356122544-f134324a6cee?auto=format&fit=crop&w=1200&q=80', 18, 72, 12450, 4.91, JSON_ARRAY('Conocer JavaScript moderno', 'Haber usado React básico', 'Tener Node.js instalado'), JSON_ARRAY('Diseñar componentes escalables', 'Crear hooks personalizados', 'Optimizar renderizados', 'Gestionar formularios complejos', 'Modelar estado de UI', 'Aplicar accesibilidad práctica', 'Organizar proyectos por dominio', 'Preparar una app para producción'), JSON_ARRAY(JSON_OBJECT('title','Arquitectura React','duration','3h','lessons',JSON_ARRAY('Estructura por dominios','Componentes de aplicación','Separación UI y lógica')), JSON_OBJECT('title','Hooks avanzados','duration','3h','lessons',JSON_ARRAY('useReducer','hooks personalizados','sincronización externa')), JSON_OBJECT('title','Estado y formularios','duration','3h','lessons',JSON_ARRAY('estado local','validaciones','errores de UX')), JSON_OBJECT('title','Rendimiento','duration','3h','lessons',JSON_ARRAY('memoización','listas grandes','profiling')), JSON_OBJECT('title','Testing','duration','3h','lessons',JSON_ARRAY('tests de componentes','mocks','casos críticos')), JSON_OBJECT('title','Proyecto final','duration','3h','lessons',JSON_ARRAY('carrito','checkout','refactor final')))),
(2, 'Node.js & APIs REST', 'Este curso enseña a diseñar APIs REST claras desde el contrato hasta el despliegue. Aunque CoderUp usa PHP en su backend académico, los principios del curso aplican a cualquier servidor: rutas bien nombradas, validación de entrada, respuestas JSON consistentes, autenticación, paginación, errores controlados y documentación. Se construye una API de catálogo con usuarios, cursos, pedidos y panel de administración. Cada decisión se explica con ejemplos reales: cuándo usar códigos 400 o 409, cómo evitar filtrar información sensible, por qué separar helpers, cómo pensar en CORS y cómo preparar endpoints para frontends desplegados en otro dominio. El objetivo final es que puedas mirar cualquier endpoint y entender si su contrato es defendible, si escala y si una interfaz React puede consumirlo sin hacks.', 'nodejs-apis-rest', 39.99, 'Intermedio', 2, 2, 3, 'https://images.unsplash.com/photo-1558494949-ef010cbdcc31?auto=format&fit=crop&w=1200&q=80', 16, 64, 9800, 4.86, JSON_ARRAY('JavaScript básico', 'Conceptos HTTP', 'Nociones de bases de datos'), JSON_ARRAY('Diseñar rutas REST', 'Validar JSON de entrada', 'Crear respuestas consistentes', 'Implementar autenticación Bearer', 'Paginar resultados', 'Gestionar errores sin HTML', 'Documentar endpoints', 'Preparar despliegue cloud'), JSON_ARRAY(JSON_OBJECT('title','Fundamentos HTTP','duration','2h','lessons',JSON_ARRAY('métodos','códigos','cabeceras')), JSON_OBJECT('title','Diseño REST','duration','3h','lessons',JSON_ARRAY('recursos','filtros','paginación')), JSON_OBJECT('title','Validación','duration','2h','lessons',JSON_ARRAY('payloads','errores','seguridad')), JSON_OBJECT('title','Autenticación','duration','3h','lessons',JSON_ARRAY('tokens','roles','sesión')), JSON_OBJECT('title','Datos','duration','3h','lessons',JSON_ARRAY('SQL','relaciones','transacciones')), JSON_OBJECT('title','Deploy','duration','3h','lessons',JSON_ARRAY('variables','CORS','logs')))),
(3, 'TypeScript Profesional', 'TypeScript Profesional se centra en escribir código que el equipo pueda mantener durante meses. El curso parte de tipos cotidianos y avanza hacia generics, discriminated unions, utilidades, contratos de API y modelado de estados. El enfoque es práctico: evitar tipos demasiado débiles, detectar errores antes de producción y construir interfaces que expliquen el dominio. Se trabaja con ejemplos de cursos, usuarios, pedidos, posts e instructores. Aprenderás a definir tipos compartidos, transformar datos del backend, proteger componentes React y mejorar la experiencia del editor. El resultado es una base sólida para proyectos Astro + React donde los datos vienen de PHP, Strapi o cualquier API externa.', 'typescript-profesional', 44.99, 'Intermedio', 1, 3, 4, 'https://images.unsplash.com/photo-1516116216624-53e697fedbea?auto=format&fit=crop&w=1200&q=80', 15, 58, 8700, 4.89, JSON_ARRAY('JavaScript moderno', 'Experiencia con React o Astro', 'Ganas de tipar datos reales'), JSON_ARRAY('Modelar entidades de negocio', 'Usar generics sin abuso', 'Crear tipos para APIs', 'Evitar any innecesario', 'Tipar formularios', 'Refactorizar con seguridad', 'Entender narrowing', 'Crear utilidades reutilizables'), JSON_ARRAY(JSON_OBJECT('title','Tipos base','duration','2h','lessons',JSON_ARRAY('interfaces','unions','narrowing')), JSON_OBJECT('title','Generics','duration','3h','lessons',JSON_ARRAY('funciones','componentes','respuestas API')), JSON_OBJECT('title','Modelado','duration','2h','lessons',JSON_ARRAY('usuarios','cursos','pedidos')), JSON_OBJECT('title','React','duration','3h','lessons',JSON_ARRAY('props','estado','formularios')), JSON_OBJECT('title','APIs','duration','3h','lessons',JSON_ARRAY('DTO','mappers','errores')), JSON_OBJECT('title','Proyecto','duration','2h','lessons',JSON_ARRAY('refactor','build','checklist')))),
(4, 'Docker & Deploy Cloud', 'Docker & Deploy Cloud convierte una aplicación local en un sistema desplegable. Se explica cómo crear imágenes, separar variables de entorno, preparar servicios PHP, conectar MySQL en Railway, desplegar frontends en Vercel y depurar errores de producción. El curso evita quedarse en comandos sueltos: cada módulo responde a problemas reales como puertos, CORS, logs, migraciones, health checks, build output y secretos. El proyecto final despliega un frontend Astro y un backend PHP con base de datos, endpoints JSON y autenticación por token. Al terminar sabrás explicar qué ocurre desde un commit hasta que una URL pública responde correctamente.', 'docker-deploy-cloud', 59.99, 'Avanzado', 3, 4, 5, 'https://images.unsplash.com/photo-1605745341112-85968b19335b?auto=format&fit=crop&w=1200&q=80', 14, 52, 6400, 4.84, JSON_ARRAY('Terminal básica', 'Git básico', 'Proyecto web para desplegar'), JSON_ARRAY('Crear imágenes Docker', 'Separar configuración por entorno', 'Desplegar en Railway', 'Publicar en Vercel', 'Configurar CORS', 'Leer logs de producción', 'Gestionar secretos', 'Preparar health checks'), JSON_ARRAY(JSON_OBJECT('title','Contenedores','duration','2h','lessons',JSON_ARRAY('imágenes','capas','puertos')), JSON_OBJECT('title','Variables','duration','2h','lessons',JSON_ARRAY('env','secretos','configuración')), JSON_OBJECT('title','Railway','duration','3h','lessons',JSON_ARRAY('servicio','MySQL','logs')), JSON_OBJECT('title','Vercel','duration','2h','lessons',JSON_ARRAY('build','dominios','variables')), JSON_OBJECT('title','Diagnóstico','duration','3h','lessons',JSON_ARRAY('CORS','500','respuestas HTML')), JSON_OBJECT('title','Entrega','duration','2h','lessons',JSON_ARRAY('checklist','rollback','documentación'))));
INSERT INTO posts (title, slug, excerpt, content, cover_image_url, author_id, category, tags, read_time, is_published, published_at) VALUES
('React en aplicaciones de cursos: arquitectura que aguanta el crecimiento', 'react-arquitectura-aplicaciones-cursos', 'Cómo estructurar una app React con componentes, hooks y datos reales sin terminar en una pantalla imposible de mantener.', '<h2>React más allá del componente bonito</h2><p>React funciona muy bien para construir interfaces rápidas, pero el verdadero reto aparece cuando la aplicación crece. Una plataforma de cursos no solo muestra tarjetas: también gestiona autenticación, carrito, checkout, estados de carga, errores del backend, filtros, formularios y páginas de detalle. Si todo vive en un único componente, cualquier cambio pequeño se vuelve arriesgado. La arquitectura empieza separando componentes visuales de lógica de negocio. Un botón de añadir al carrito no debería conocer cómo se persiste una orden, y una página de curso no debería repetir la validación del usuario.</p><p>Una buena estrategia consiste en trabajar por dominios. Cursos, carrito, autenticación y pedidos tienen modelos propios. Cada dominio expone funciones claras y la interfaz las consume. Esto ayuda a testear, reduce dependencias accidentales y permite cambiar el backend sin reescribir toda la UI. También conviene reservar los hooks para coordinar estado y efectos, no para esconder cualquier cosa. Un hook bien diseñado explica qué devuelve, cuándo carga y cómo gestiona errores.</p><p>El rendimiento se cuida evitando renderizados innecesarios, dividiendo componentes grandes y usando datos derivados con criterio. No se trata de añadir memoización por reflejo, sino de observar dónde hay coste real. En una lista de cursos con filtros, por ejemplo, tiene sentido diferir búsquedas o paginar. En un formulario pequeño, no.</p><p>La accesibilidad también forma parte de la arquitectura. Labels, mensajes de error, estados disabled y feedback visible no son detalles estéticos: son parte del contrato de la interfaz. Una aplicación defendible en un TFG debe poder explicar cómo reacciona cuando el backend falla, cuando el usuario escribe datos incorrectos y cuando un flujo requiere autenticación. React no resuelve esas decisiones por sí solo, pero ofrece una base excelente para organizarlas si se trabaja con intención.</p><p>La clave final es mantener una frontera limpia entre UI y datos. Si mañana los cursos vienen de PHP, Strapi o un servicio externo, la página debería seguir mostrando el mismo modelo. Esa capa de transformación es pequeña, pero ahorra semanas de deuda técnica.</p>', 'https://images.unsplash.com/photo-1633356122544-f134324a6cee?auto=format&fit=crop&w=1200&q=80', 2, 'React', JSON_ARRAY('React','Arquitectura','Frontend'), 7, TRUE, '2026-03-01 10:00:00'),
('TypeScript como documentación viva del producto', 'typescript-documentacion-viva-producto', 'Por qué los tipos bien diseñados reducen errores, mejoran la comunicación y hacen más sencillo defender una aplicación.', '<h2>Tipos que explican decisiones</h2><p>TypeScript no consiste únicamente en satisfacer al compilador. En un proyecto real, los tipos funcionan como documentación viva: describen qué es un curso, qué datos tiene un usuario, cómo se representa una orden y qué espera recibir un componente. Cuando esos tipos están cerca del dominio, el equipo puede leer el código y entender el producto sin perseguir valores por toda la aplicación.</p><p>El primer beneficio aparece al consumir APIs. Un backend PHP puede devolver JSON correcto, errores controlados o respuestas inesperadas. Si el frontend transforma esa respuesta hacia un modelo `Course`, `BlogPost` o `Instructor`, el resto de la interfaz trabaja con datos estables. Esa transformación también permite normalizar nombres, convertir números que llegan como strings y proporcionar fallbacks razonables. El tipo no sustituye a la validación en runtime, pero obliga a pensar en los casos posibles.</p><p>Otro punto importante es evitar el abuso de `any`. A veces parece acelerar, pero en realidad aplaza el problema. Un `any` en una respuesta de autenticación puede esconder que el backend devuelve `{ user, token }` mientras el componente espera directamente `{ id, email }`. Un tipo explícito hace visible el contrato y facilita refactors seguros. Las uniones discriminadas son especialmente útiles para estados de UI: loading, success, error e idle tienen campos distintos, y TypeScript puede impedir que se muestre un mensaje inexistente.</p><p>Los generics deben usarse con moderación. Son muy útiles para respuestas API, formularios reutilizables o listas paginadas, pero pueden volver el código opaco si intentan resolver todos los casos. La regla práctica es sencilla: si el generic mejora la lectura y evita duplicación real, adelante; si obliga a descifrar el tipo antes de entender la función, quizá conviene simplificar.</p><p>En una defensa académica, TypeScript aporta un argumento fuerte: el proyecto no solo funciona visualmente, también expresa sus contratos. Esa claridad reduce bugs, ayuda a integrar backend y frontend, y demuestra criterio profesional.</p>', 'https://images.unsplash.com/photo-1516116216624-53e697fedbea?auto=format&fit=crop&w=1200&q=80', 4, 'TypeScript', JSON_ARRAY('TypeScript','Calidad','Producto'), 6, TRUE, '2026-03-05 10:00:00'),
('CSS moderno: diseño oscuro, responsive y mantenible', 'css-moderno-dark-responsive', 'Cómo construir interfaces dark mode profesionales con Tailwind, jerarquía visual y componentes consistentes.', '<h2>Diseñar para leer y repetir</h2><p>Un diseño oscuro puede parecer sencillo: fondo negro, texto blanco y un color de acento. Sin embargo, una interfaz profesional necesita más matices. El contraste debe permitir lectura larga, los bordes deben separar zonas sin generar ruido, y los estados interactivos deben ser claros. En una plataforma de cursos, el usuario explora, compara, compra y vuelve a consultar su cuenta. Eso exige una experiencia consistente, no una colección de cards decorativas.</p><p>Tailwind ayuda porque convierte decisiones visuales en clases pequeñas y repetibles. El peligro está en usarlo sin sistema. Si cada tarjeta inventa su propio padding, radio y color de borde, el producto pierde coherencia. Una buena práctica es identificar patrones: paneles principales, tarjetas de curso, botones primarios, campos de formulario y mensajes de estado. Cada patrón debe tener variaciones mínimas y predecibles.</p><p>El responsive no es solo hacer que algo quepa. Hay que decidir qué información aparece primero. En móvil, el precio y el botón de compra de un curso deben ser accesibles; el temario puede ir debajo. En desktop, una columna lateral ayuda a comparar datos sin perder contexto. También importan las dimensiones estables: botones, iconos y contenedores no deberían saltar cuando cambia un texto.</p><p>El color verde puede ser una firma visual poderosa, pero conviene combinarlo con grises, blanco y algún acento secundario moderado para evitar monotonía. Los mensajes de error deben destacar en rojo, los éxitos en verde y los estados neutros en gris. Así el usuario no interpreta todo como una llamada a la acción.</p><p>CSS moderno también significa accesibilidad. Focus visible, labels asociados, tamaños legibles y contraste suficiente son requisitos, no extras. Una interfaz que se defiende bien es aquella donde el diseño acompaña al flujo y no oculta problemas de usabilidad.</p>', 'https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=1200&q=80', 2, 'CSS', JSON_ARRAY('CSS','Tailwind','UI'), 6, TRUE, '2026-03-10 10:00:00'),
('Git para proyectos académicos que parecen profesionales', 'git-proyectos-academicos-profesionales', 'Ramas, commits y revisión de cambios para entregar un TFG con trazabilidad real y menos riesgo.', '<h2>Git como historial de decisiones</h2><p>Git no es solo una herramienta para subir código. En un proyecto académico serio, el historial demuestra evolución: cuándo se añadió el backend, cuándo se corrigió la autenticación, cuándo se limpiaron textos de defensa y cuándo se integró una nueva funcionalidad. Un commit bien escrito cuenta una decisión y permite volver atrás si algo falla.</p><p>El primer hábito útil es trabajar en cambios pequeños. Si se mezclan recuperación de contraseña, rediseño del home y migraciones SQL en el mismo commit, revisar se vuelve difícil. En cambio, un commit para token Bearer, otro para endpoints de posts y otro para páginas de instructores permite entender el proyecto de un vistazo. También facilita explicar en una defensa qué problema resolvía cada parte.</p><p>Las ramas ayudan cuando hay riesgo o colaboración, pero incluso en `main` se puede trabajar con disciplina si el proyecto es individual. Antes de commitear conviene ejecutar build, revisar `git diff --stat` y comprobar que no se han añadido secretos. El `.env` real no debe subirse; el `.env.example` sí, porque documenta qué variables necesita Railway o Vercel.</p><p>Los conflictos no son fracasos, son señales de que dos líneas de trabajo tocaron la misma zona. Resolverlos bien implica entender el código, no aceptar una versión al azar. Cuando se integra trabajo remoto, hay que conservar lo que aporta y volver a validar. En proyectos con despliegue automático, cada push puede activar producción, así que el build local es una red de seguridad básica.</p><p>Un buen uso de Git transmite madurez. El profesor no ve solo una web funcionando, ve un proceso: iteraciones, correcciones, pruebas y una ruta clara desde la idea inicial hasta el producto final.</p>', 'https://images.unsplash.com/photo-1556075798-4825dfaaf498?auto=format&fit=crop&w=1200&q=80', 5, 'Git', JSON_ARRAY('Git','Workflow','TFG'), 6, TRUE, '2026-03-15 10:00:00'),
('APIs con PHP: JSON consistente, CORS y errores controlados', 'apis-php-json-cors-errores', 'Lecciones prácticas para que un backend PHP desplegado en Railway funcione bien con un frontend en Vercel.', '<h2>El contrato importa más que el lenguaje</h2><p>PHP sigue siendo una opción válida para backends pequeños y medianos si se trabaja con disciplina. El problema no suele ser PHP, sino la falta de contrato. Un frontend en Vercel necesita respuestas JSON, cabeceras CORS correctas, códigos HTTP coherentes y autenticación compatible entre dominios. Si un endpoint devuelve HTML por un fatal error, React no puede distinguir si falló la validación o si la base de datos no existe.</p><p>El primer principio es centralizar respuestas. Funciones como `sendSuccess` y `sendError` evitan formatos distintos en cada archivo. También permiten añadir detalles solo en desarrollo y mantener producción limpia. El segundo principio es leer el body correctamente. Cuando el cliente envía `Content-Type: application/json`, el backend debe leer `php://input`, decodificarlo y validar que el resultado sea un array. Si se recibe una cadena mal serializada, el error debe ser claro.</p><p>CORS merece atención especial. Vercel y Railway viven en dominios distintos, por lo que el backend debe aceptar el origen del frontend y permitir `Authorization`. Las cookies de sesión pueden fallar entre dominios si no se configuran con precisión, por eso un token Bearer suele ser más sencillo para un TFG: el login devuelve token, el frontend lo guarda y cada petición lo envía en una cabecera.</p><p>La base de datos también forma parte del contrato. Las migraciones deben crear columnas como `remember_token`, `reset_token` o `instructor_id` antes de que el código las consulte. En producción conviene tener SQL de migración separado para ejecutarlo directamente. Y si algo falla, el backend debe responder JSON con un mensaje controlado, nunca una página HTML de error.</p><p>Una API defendible no es la que tiene más endpoints, sino la que falla bien, se entiende rápido y permite que el frontend evolucione sin adivinar comportamientos.</p>', 'https://images.unsplash.com/photo-1558494949-ef010cbdcc31?auto=format&fit=crop&w=1200&q=80', 3, 'APIs', JSON_ARRAY('PHP','APIs','CORS'), 7, TRUE, '2026-03-20 10:00:00'),
('DevOps mínimo para Vercel, Railway y bases de datos', 'devops-vercel-railway-bases-datos', 'Qué revisar cuando una app funciona localmente pero falla al desplegar frontend, backend y MySQL por separado.', '<h2>Producción cambia las reglas</h2><p>Una aplicación que funciona en local todavía no está terminada. En producción aparecen dominios distintos, variables de entorno, bases de datos vacías, rutas relativas, puertos, logs y tiempos de despliegue. Vercel sirve el frontend como estático o SSR, Railway ejecuta el backend y MySQL vive como servicio separado. Cada pieza puede estar bien por separado y aun así fallar en conjunto.</p><p>El primer paso DevOps es listar dependencias: `PUBLIC_API_URL` en Vercel, credenciales MySQL en Railway, `FRONTEND_URL` para CORS y una clave `AUTH_SECRET` estable. Si una variable falta, el error debe verse en logs o en una respuesta JSON. El segundo paso es preparar la base de datos. No basta con tener código que consulte `users`; esa tabla debe existir. Por eso conviene mantener `schema.sql`, `seed.sql` y migraciones incrementales.</p><p>Los logs son la herramienta principal. Un mensaje del navegador como “respuesta no válida” suele esconder que el backend devolvió HTML por un fatal error. Hacer una prueba con `curl -i` al endpoint real permite ver cabeceras, status y cuerpo. Esa observación ahorra horas de suposiciones. También ayuda comprobar si Railway ya desplegó el último commit o sigue sirviendo una versión antigua.</p><p>El despliegue debe ser repetible. Cada push a `main` debería construir, ejecutar checks básicos y publicar. Antes del push, un build local reduce riesgos. Después del push, una prueba de endpoint crítico confirma que la versión pública coincide con el código. Para un TFG, este flujo demuestra que el proyecto no depende de magia local.</p><p>DevOps mínimo no significa aprender Kubernetes desde el día uno. Significa entender configuración, logs, migraciones y contratos entre servicios. Con eso, un proyecto académico gana fiabilidad y credibilidad.</p>', 'https://images.unsplash.com/photo-1605745341112-85968b19335b?auto=format&fit=crop&w=1200&q=80', 5, 'DevOps', JSON_ARRAY('DevOps','Vercel','Railway'), 7, TRUE, '2026-03-25 10:00:00');
